      "message.shareLinkReady": "\u0394\u03B7\u03BC\u03B9\u03BF\u03C5\u03C1\u03B3\u03AE\u03B8\u03B7\u03BA\u03B5 \u03C3\u03CD\u03BD\u03B4\u03B5\u03C3\u03BC\u03BF\u03C2 \u03BA\u03BF\u03B9\u03BD\u03AE\u03C2 \u03C7\u03C1\u03AE\u03C3\u03B7\u03C2 \u03BC\u03CC\u03BD\u03BF \u03B3\u03B9\u03B1 \u03B1\u03BD\u03AC\u03B3\u03BD\u03C9\u03C3\u03B7.",
      "message.shareLinkRevoked": "\u039F \u03C3\u03CD\u03BD\u03B4\u03B5\u03C3\u03BC\u03BF\u03C2 \u03BA\u03BF\u03B9\u03BD\u03AE\u03C2 \u03C7\u03C1\u03AE\u03C3\u03B7\u03C2 \u03B1\u03BD\u03B1\u03BA\u03BB\u03AE\u03B8\u03B7\u03BA\u03B5.",
      "message.stepUpdatedLocally": "\u03A4\u03BF \u03B2\u03AE\u03BC\u03B1 \u03B5\u03BD\u03B7\u03BC\u03B5\u03C1\u03CE\u03B8\u03B7\u03BA\u03B5 \u03C4\u03BF\u03C0\u03B9\u03BA\u03AC. \u0391\u03C0\u03BF\u03B8\u03B7\u03BA\u03B5\u03CD\u03C3\u03C4\u03B5 \u03C4\u03BF \u03C3\u03C7\u03AD\u03B4\u03B9\u03BF \u03B3\u03B9\u03B1 \u03BD\u03B1 \u03C3\u03C5\u03BD\u03B5\u03C7\u03AF\u03C3\u03B5\u03C4\u03B5 \u03C4\u03B7\u03BD \u03B1\u03BB\u03BB\u03B1\u03B3\u03AE.",
      "message.stopRequested": "\u0396\u03B7\u03C4\u03AE\u03B8\u03B7\u03BA\u03B5 \u03B4\u03B9\u03B1\u03BA\u03BF\u03C0\u03AE \u03BC\u03B5\u03C4\u03AC \u03C4\u03BF \u03C4\u03C1\u03AD\u03C7\u03BF\u03BD \u03B2\u03AE\u03BC\u03B1.",
      "message.noShareLinkAvailable": "\u0394\u03B5\u03BD \u03C5\u03C0\u03AC\u03C1\u03C7\u03B5\u03B9 \u03B5\u03BD\u03B5\u03C1\u03B3\u03CC\u03C2 \u03C3\u03CD\u03BD\u03B4\u03B5\u03C3\u03BC\u03BF\u03C2 \u03BA\u03BF\u03B9\u03BD\u03AE\u03C2 \u03C7\u03C1\u03AE\u03C3\u03B7\u03C2 \u03B3\u03B9\u03B1 \u03B1\u03C5\u03C4\u03CC \u03C4\u03BF \u03AD\u03C1\u03B3\u03BF.",
      "option.allowPushAfterSafeRuns": "\u0395\u03C0\u03B9\u03C4\u03C1\u03AD\u03C8\u03C4\u03B5 \u03C4\u03B7\u03BD \u03CE\u03B8\u03B7\u03C3\u03B7 \u03BC\u03B5\u03C4\u03AC \u03B1\u03C0\u03CC \u03B1\u03C3\u03C6\u03B1\u03BB\u03B5\u03AF\u03C2 \u03B4\u03B9\u03B1\u03B4\u03C1\u03BF\u03BC\u03AD\u03C2",
      "option.generateWordReport": "\u0394\u03B7\u03BC\u03B9\u03BF\u03C5\u03C1\u03B3\u03AF\u03B1 \u03B1\u03BD\u03B1\u03C6\u03BF\u03C1\u03AC\u03C2 Word",
      "option.requireCheckpointApproval": "\u0391\u03C0\u03B1\u03B9\u03C4\u03B5\u03AF\u03C4\u03B1\u03B9 \u03AD\u03B3\u03BA\u03C1\u03B9\u03C3\u03B7 \u03C3\u03B7\u03BC\u03B5\u03AF\u03BF\u03C5 \u03B5\u03BB\u03AD\u03B3\u03C7\u03BF\u03C5",
      "option.useFastMode": "\u03A7\u03C1\u03AE\u03C3\u03B7 /\u03B3\u03C1\u03AE\u03B3\u03BF\u03C1\u03BF",
      "project.none": "\u039A\u03B1\u03BD\u03AD\u03BD\u03B1 \u0388\u03C1\u03B3\u03BF",
      "prompt.confirmCloseout": "\u0395\u03BA\u03C4\u03AD\u03BB\u03B5\u03C3\u03B7 \u03C4\u03B5\u03BB\u03B9\u03BA\u03BF\u03CD \u03BA\u03BB\u03B5\u03B9\u03C3\u03AF\u03BC\u03B1\u03C4\u03BF\u03C2 \u03C4\u03CE\u03C1\u03B1; \u0391\u03C5\u03C4\u03CC \u03B8\u03B1 \u03BA\u03AC\u03BD\u03B5\u03B9 \u03C4\u03BF\u03BD \u03C4\u03B5\u03BB\u03B9\u03BA\u03CC \u03BA\u03B1\u03B8\u03B1\u03C1\u03B9\u03C3\u03BC\u03CC, \u03C4\u03B7\u03BD \u03B5\u03C0\u03B1\u03BB\u03AE\u03B8\u03B5\u03C5\u03C3\u03B7, \u03C4\u03BF\u03C5\u03C2 \u03B5\u03BB\u03AD\u03B3\u03C7\u03BF\u03C5\u03C2 \u03BA\u03B1\u03C0\u03BD\u03BF\u03CD, \u03CC\u03C4\u03B1\u03BD \u03B5\u03AF\u03BD\u03B1\u03B9 \u03B4\u03C5\u03BD\u03B1\u03C4\u03CC\u03BD, \u03BA\u03B1\u03B9 \u03C4\u03B7\u03BD \u03B5\u03C1\u03B3\u03B1\u03C3\u03AF\u03B1 \u03C0\u03B1\u03C1\u03AC\u03B4\u03BF\u03C3\u03B7\u03C2.",
      "prompt.confirmRegeneratePlan": "\u0391\u03BD\u03C4\u03B9\u03BA\u03B1\u03C4\u03AC\u03C3\u03C4\u03B1\u03C3\u03B7 \u03C4\u03BF\u03C5 \u03C4\u03C1\u03AD\u03C7\u03BF\u03BD\u03C4\u03BF\u03C2 \u03BC\u03B7 \u03B5\u03BA\u03BA\u03B9\u03BD\u03B7\u03BC\u03AD\u03BD\u03BF\u03C5 \u03C0\u03C1\u03BF\u03B3\u03C1\u03AC\u03BC\u03BC\u03B1\u03C4\u03BF\u03C2 \u03BC\u03B5 \u03AD\u03BD\u03B1 \u03BD\u03AD\u03BF \u03C3\u03C7\u03AD\u03B4\u03B9\u03BF \u03C0\u03BF\u03C5 \u03B4\u03B7\u03BC\u03B9\u03BF\u03C5\u03C1\u03B3\u03AE\u03B8\u03B7\u03BA\u03B5 \u03B1\u03C0\u03CC \u03C4\u03BF\u03BD Codex;",
      "prompt.confirmResetPlan": "\u0395\u03C0\u03B1\u03BD\u03B1\u03C6\u03BF\u03C1\u03AC \u03C4\u03B7\u03C2 \u03B1\u03C0\u03BF\u03B8\u03B7\u03BA\u03B5\u03C5\u03BC\u03AD\u03BD\u03B7\u03C2 \u03C0\u03C1\u03BF\u03C4\u03C1\u03BF\u03C0\u03AE\u03C2 \u03BA\u03B1\u03B9 \u03BA\u03B1\u03C4\u03AC\u03C1\u03B3\u03B7\u03C3\u03B7 \u03CC\u03BB\u03C9\u03BD \u03C4\u03C9\u03BD \u03B2\u03B7\u03BC\u03AC\u03C4\u03C9\u03BD \u03B5\u03BA\u03C4\u03AD\u03BB\u03B5\u03C3\u03B7\u03C2 \u03B3\u03B9\u03B1 \u03B1\u03C5\u03C4\u03CC \u03C4\u03BF \u03AD\u03C1\u03B3\u03BF;",
      "prompt.confirmDeleteProject": "\u039A\u03B1\u03C4\u03AC\u03C1\u03B3\u03B7\u03C3\u03B7 \u03B1\u03C5\u03C4\u03BF\u03CD \u03C4\u03BF\u03C5 \u03AD\u03C1\u03B3\u03BF\u03C5 \u03B1\u03C0\u03CC \u03C4\u03BF jakal-flow; \u03A4\u03B1 \u03B4\u03B9\u03B1\u03C7\u03B5\u03B9\u03C1\u03B9\u03B6\u03CC\u03BC\u03B5\u03BD\u03B1 \u03AD\u03B3\u03B3\u03C1\u03B1\u03C6\u03B1, \u03C4\u03B1 \u03B1\u03C1\u03C7\u03B5\u03AF\u03B1 \u03BA\u03B1\u03C4\u03B1\u03B3\u03C1\u03B1\u03C6\u03AE\u03C2 \u03BA\u03B1\u03B9 \u03B7 \u03BA\u03B1\u03C4\u03AC\u03C3\u03C4\u03B1\u03C3\u03B7 \u03B8\u03B1 \u03B4\u03B9\u03B1\u03B3\u03C1\u03B1\u03C6\u03BF\u03CD\u03BD, \u03B1\u03BB\u03BB\u03AC \u03BF \u03B1\u03C1\u03C7\u03B9\u03BA\u03CC\u03C2 \u03C6\u03AC\u03BA\u03B5\u03BB\u03BF\u03C2 \u03C4\u03BF\u03C5 \u03B1\u03C0\u03BF\u03B8\u03B5\u03C4\u03B7\u03C1\u03AF\u03BF\u03C5 \u03B8\u03B1 \u03C0\u03B1\u03C1\u03B1\u03BC\u03B5\u03AF\u03BD\u03B5\u03B9 \u03C3\u03C4\u03B7 \u03B8\u03AD\u03C3\u03B7 \u03C4\u03BF\u03C5.",
      "prompt.confirmDeleteAllProjects": "\u039A\u03B1\u03C4\u03AC\u03C1\u03B3\u03B7\u03C3\u03B7 \u03CC\u03BB\u03C9\u03BD \u03C4\u03C9\u03BD \u03AD\u03C1\u03B3\u03C9\u03BD \u03B1\u03C0\u03CC \u03C4\u03BF jakal-flow; \u03A4\u03B1 \u03B4\u03B9\u03B1\u03C7\u03B5\u03B9\u03C1\u03B9\u03B6\u03CC\u03BC\u03B5\u03BD\u03B1 \u03AD\u03B3\u03B3\u03C1\u03B1\u03C6\u03B1, \u03C4\u03B1 \u03B1\u03C1\u03C7\u03B5\u03AF\u03B1 \u03BA\u03B1\u03C4\u03B1\u03B3\u03C1\u03B1\u03C6\u03AE\u03C2 \u03BA\u03B1\u03B9 \u03B7 \u03BA\u03B1\u03C4\u03AC\u03C3\u03C4\u03B1\u03C3\u03B7 \u03B8\u03B1 \u03B4\u03B9\u03B1\u03B3\u03C1\u03B1\u03C6\u03BF\u03CD\u03BD, \u03B1\u03BB\u03BB\u03AC \u03BF\u03B9 \u03B1\u03C1\u03C7\u03B9\u03BA\u03BF\u03AF \u03C6\u03AC\u03BA\u03B5\u03BB\u03BF\u03B9 \u03C4\u03BF\u03C5 \u03B1\u03C0\u03BF\u03B8\u03B5\u03C4\u03B7\u03C1\u03AF\u03BF\u03C5 \u03B8\u03B1 \u03C0\u03B1\u03C1\u03B1\u03BC\u03B5\u03AF\u03BD\u03BF\u03C5\u03BD \u03C3\u03C4\u03B7 \u03B8\u03AD\u03C3\u03B7 \u03C4\u03BF\u03C5\u03C2.",
