      "message.shareLinkReady": "\u05E0\u05D5\u05E6\u05E8 \u05E7\u05D9\u05E9\u05D5\u05E8 \u05E9\u05D9\u05EA\u05D5\u05E3 \u05DC\u05E7\u05E8\u05D9\u05D0\u05D4 \u05D1\u05DC\u05D1\u05D3.",
