      "message.stopRequested": "\u05D4\u05EA\u05D1\u05E7\u05E9\u05D4 \u05DC\u05D4\u05E4\u05E1\u05D9\u05E7 \u05DC\u05D0\u05D7\u05E8 \u05D4\u05E9\u05DC\u05D1 \u05D4\u05E0\u05D5\u05DB\u05D7\u05D9.",
