      "message.stopRequested": "\u0417\u0430\u0445\u0442\u0458\u0435\u0432 \u0437\u0430 \u0437\u0430\u0443\u0441\u0442\u0430\u0432\u0459\u0430\u045A\u0435 \u043D\u0430\u043A\u043E\u043D \u0442\u0440\u0435\u043D\u0443\u0442\u043D\u043E\u0433 \u043A\u043E\u0440\u0430\u043A\u0430.",
      "message.noShareLinkAvailable": "\u0417\u0430 \u043E\u0432\u0430\u0458 \u043F\u0440\u043E\u0458\u0435\u043A\u0430\u0442 \u043D\u0438\u0458\u0435 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u0430 \u0430\u043A\u0442\u0438\u0432\u043D\u0430 \u0432\u0435\u0437\u0430 \u0437\u0430 \u0434\u0435\u0459\u0435\u045A\u0435.",
