      "option.generateWordReport": "\u041A\u0440\u0435\u0438\u0440\u0430\u045A\u0435 \u0412\u043E\u0440\u0434 \u0438\u0437\u0432\u0435\u0448\u0442\u0430\u0458\u0430",
