      "option.useFastMode": "\u041A\u043E\u0440\u0438\u0441\u0442\u0438\u0442\u0435 /\u0431\u0440\u0437\u043E",
      "project.none": "\u041D\u043E \u041F\u0440\u043E\u0458\u0435\u0446\u0442",
      "prompt.confirmCloseout": "\u041F\u043E\u043A\u0440\u0435\u043D\u0443\u0442\u0438 \u043A\u043E\u043D\u0430\u0447\u043D\u043E \u0437\u0430\u0442\u0432\u0430\u0440\u0430\u045A\u0435 \u0441\u0430\u0434\u0430? \u041E\u0432\u043E \u045B\u0435 \u043E\u0431\u0430\u0432\u0438\u0442\u0438 \u0437\u0430\u0432\u0440\u0448\u043D\u043E \u0447\u0438\u0448\u045B\u0435\u045A\u0435, \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0458\u0443, \u043F\u0440\u043E\u0432\u0435\u0440\u0443 \u0434\u0438\u043C\u0430 \u043A\u0430\u0434\u0430 \u0458\u0435 \u0442\u043E \u043C\u043E\u0433\u0443\u045B\u0435 \u0438 \u0440\u0430\u0434 \u043F\u0440\u0438\u043C\u043E\u043F\u0440\u0435\u0434\u0430\u0458\u0435.",
      "prompt.confirmRegeneratePlan": "\u0417\u0430\u043C\u0435\u043D\u0438\u0442\u0438 \u0442\u0440\u0435\u043D\u0443\u0442\u043D\u0438 \u043D\u0435\u043F\u043E\u043A\u0440\u0435\u043D\u0443\u0442\u0438 \u043F\u043B\u0430\u043D \u043D\u043E\u0432\u0438\u043C \u043F\u043B\u0430\u043D\u043E\u043C \u043A\u043E\u0458\u0438 \u0458\u0435 \u0433\u0435\u043D\u0435\u0440\u0438\u0441\u0430\u043E \u0426\u043E\u0434\u0435\u043A?",
      "prompt.confirmResetPlan": "\u0416\u0435\u043B\u0438\u0442\u0435 \u043B\u0438 \u0434\u0430 \u0440\u0435\u0441\u0435\u0442\u0443\u0458\u0435\u0442\u0435 \u0441\u0430\u0447\u0443\u0432\u0430\u043D\u0438 \u0443\u043F\u0438\u0442 \u0438 \u0443\u043A\u043B\u043E\u043D\u0438\u0442\u0435 \u0441\u0432\u0435 \u043A\u043E\u0440\u0430\u043A\u0435 \u0438\u0437\u0432\u0440\u0448\u0435\u045A\u0430 \u0437\u0430 \u043E\u0432\u0430\u0458 \u043F\u0440\u043E\u0458\u0435\u043A\u0430\u0442?",
      "prompt.confirmDeleteProject": "\u0423\u043A\u043B\u043E\u043D\u0438\u0442\u0438 \u043E\u0432\u0430\u0458 \u043F\u0440\u043E\u0458\u0435\u043A\u0430\u0442 \u0441\u0430 \u0458\u0430\u043A\u0430\u043B-\u0444\u043B\u043E\u0432-\u0430? \u0423\u043F\u0440\u0430\u0432\u0459\u0430\u043D\u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0438, \u0435\u0432\u0438\u0434\u0435\u043D\u0446\u0438\u0458\u0435 \u0438 \u0441\u0442\u0430\u045A\u0435 \u045B\u0435 \u0431\u0438\u0442\u0438 \u0438\u0437\u0431\u0440\u0438\u0441\u0430\u043D\u0438, \u0430\u043B\u0438 \u045B\u0435 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u043D\u0430 \u0444\u0430\u0441\u0446\u0438\u043A\u043B\u0430 \u0441\u043F\u0440\u0435\u043C\u0438\u0448\u0442\u0430 \u043E\u0441\u0442\u0430\u0442\u0438 \u043D\u0430 \u043C\u0435\u0441\u0442\u0443.",
